sql:
SELECT user_id, username, role
FROM users
WHERE role = 'admin' AND username NOT IN ('admin', 'system');

external_knowledge:
; "players" refers to the individuals included in the users table;
; "overall points" means the sum of scores achieved by each user in different fixtures;
; "the most recent game date" is the latest kickoff time of any game a player has participated in

sql:
SELECT score, rank
FROM user_scores
WHERE user_id = 0 AND fixture_id = 0;

SELECT team_name
FROM user_teams
WHERE user_id = 1;

SELECT team_id, COUNT(*) AS player_count
FROM team_players
GROUP BY team_id;

SELECT COUNT(DISTINCT player_id) AS players_with_goals_and_assists
FROM player_fixtures
WHERE goals_scored > 0 AND assists > 0;

SELECT us.user_id, us.score, us.rank
FROM user_scores us
INNER JOIN fixtures f ON us.fixture_id = f.fixture_id
WHERE f.gameweek = (
    SELECT MAX(gameweek) FROM fixtures
) AND us.user_id = (
    SELECT user_id FROM users WHERE username = 'john_doe'
);

external_knowledge:
1. In the context of fantasy sports leagues, the champion is the user with the highest points at the end of the league period;
2. The term "captain" is used metaphorically to refer to the user leading their team in the league, while "squad's stars" denote the standout player performances;
3. "Towing the banner of victory" is a metaphor indicating the user's achievement of the top rank in the league;
4. "Nuances of their performance" refer to detailed statistics like own goals, penalty outcomes, and defensive actions (clean sheets, saves) that impact the overall ranking;
5. "Elevated their team to the pinnacle of the league" refers to the user's team securing the top position based on accumulated points.

sql:
SELECT user_score_id, user_id, fixture_id, score, rank
FROM user_scores
WHERE fixture_id IN (
    SELECT fixture_id
    FROM fixtures
    WHERE gameweek = (
        SELECT MAX(gameweek)
        FROM fixtures
    )
);

SELECT team_name
FROM user_teams
WHERE user_id = 1;

SELECT player_fixtures.fixture_id, player_fixtures.player_id, scores.score
FROM player_fixtures
INNER JOIN scores ON player_fixtures.player_id = scores.player_id;
